info.narration:
      [
      {ห้องกักกันของ $0 มีพายุหิมะที่หนาวเหน็บ},
      {ห้องกักกันของ $0 ส่องแสงระยิบระยับด้วยน้ำแข็งและน้ำค้างแข็ง},
      {ถ้า Kai ไม่สามารถสร้างประติมากรรมแห่ง "นิรันดร" ด้วยเกล็ดน้ำแข็งได้ เขาคงจะได้รับของขวัญจากโลกใบนี้}
      ]

info.narrationa:
      [
      {พระราชวังของ $0 หนาวเย็นและโดดเดี่ยว #0 อยากจะออกจากที่แห่งนี้ให้เร็วที่สุดเท่าที่จะทำได้},
      {ถนนไปยังพระราชวังของ $0 หนาวจัดและยังคงยาวนาน #0 โหยหาความอบอุ่น}
      ]

info.narration:
      [
      {Gerda ผู้กล้าหาญและแข็งแกร่งกว่าใครๆ จะต่อสู้เพื่อ Kai ที่ถูกขังอยู่ในพระราชวังหิมะ}
      ]

      [
      {ฤดูใบไม้ผลิมาถึงพร้อมกับกุหลาบที่ผลิบาน Gerda และ Kai จูงมือกันแล้วเดินกลับบ้าน}
      ]

      [
      {Gerda และ Kai ไม่สามารถเอาชนะ $0 ได้ พวกเขากลายเป็นเศษน้ำแข็งในมือของเธอและจะไม่มีวันออกจากพระราชวังหิมะ}
      ]

      [
      {ตราบใดที่ Kai ยังคงติดอยู่ในพระราชวังหิมะ Gerda จะต้องเผชิญหน้ากับการดวลกับ $0 อย่างหลีกเลี่ยงไม่ได้ในที่สุด}
      ]

observe.desc:
      [
      {ราชินีที่อาศัยอยู่เพียงลำพังในป่าฤดูหนาวที่หนาวจัด}
      ]

      [
      {เช่นเดียวกับที่ทุกเรื่องราวเริ่มต้น Kai เป็นเด็กที่มีหัวใจที่อ่อนโยน เมื่อเศษกระจกที่ทำโดยนางฟ้าชั่วร้ายกระจัดกระจายไปบนหัวใจของทุกคน Kai ก็เริ่มเห็นสิ่งที่ไม่ต้องการเห็น หรือไม่จำเป็นต้องเห็น เขาออกจากหมู่บ้านเล็กๆ ที่เขาเติบโตมา

ท่ามกลางพายุหิมะที่ไม่ปรานี Kai ได้พบกับราชินีหิมะ เขารู้สึกอยากรู้อยากเห็นเกี่ยวกับโลกที่อยู่นอกเหนือความรู้ของเขา เขารู้สึกราวกับว่าทุกสิ่งที่เขารู้มีค่าน้อยมาก}
      ]
